import{_ as a,o,c as t,ag as r}from"./chunks/framework.DXGyWiRo.js";const f=JSON.parse('{"title":"Info","description":"","frontmatter":{},"headers":[],"relativePath":"info.md","filePath":"info.md"}'),i={name:"info.md"};function n(s,e,l,c,u,d){return o(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="info" tabindex="-1">Info <a class="header-anchor" href="#info" aria-label="Permalink to &quot;Info&quot;">​</a></h1><p><strong>viraled.lol</strong> is an exclusive Content Creator Networking Platform built for established creators to grow, network, and streamline their publishing workflows.</p><h2 id="the-first-stage-gaining-access" tabindex="-1">The First Stage: Gaining Access <a class="header-anchor" href="#the-first-stage-gaining-access" aria-label="Permalink to &quot;The First Stage: Gaining Access&quot;">​</a></h2><p>We believe in quality and curation. Gaining access requires verifying your audience footprint:</p><ol><li><strong>Sign Up</strong>: Register using your email and password, or quickly authorize via Discord.</li><li><strong>Stat Display Stage</strong>: You will have exactly 5 slots to authorize your main social profiles (Instagram accounts, YouTube channels, or TikTok accounts).</li><li><strong>Viraled Member</strong>: If your combined following across those 5 slots reaches <strong>150,000</strong>, you unlock the &quot;Viraled Member&quot; rank and gain full platform access.</li></ol><h2 id="your-public-profile" tabindex="-1">Your Public Profile <a class="header-anchor" href="#your-public-profile" aria-label="Permalink to &quot;Your Public Profile&quot;">​</a></h2><p>Once you are a Viraled Member, a public creator profile is generated for others to see. In your site settings, you have full control over this profile—you can upload a custom profile picture and explicitly hide any specific statistics or content you prefer not to display.</p><h2 id="core-features" tabindex="-1">Core Features <a class="header-anchor" href="#core-features" aria-label="Permalink to &quot;Core Features&quot;">​</a></h2><p>Once inside, you navigate your success through three primary hubs:</p><h3 id="_1-creator-dashboard" tabindex="-1">1. Creator Dashboard <a class="header-anchor" href="#_1-creator-dashboard" aria-label="Permalink to &quot;1. Creator Dashboard&quot;">​</a></h3><p>A highly efficient center for content distribution.</p><ul><li>Upload video files directly and schedule them to publish on YouTube, TikTok, and other platforms from one place.</li><li>Batch select multiple videos (e.g. from TikTok) and push them over to YouTube seamlessly.</li><li>Confirm and meticulously manage the schedule, title, description, and hashtags for each piece of content before it goes live.</li></ul><h3 id="_2-connect-and-network" tabindex="-1">2. Connect and Network <a class="header-anchor" href="#_2-connect-and-network" aria-label="Permalink to &quot;2. Connect and Network&quot;">​</a></h3><p>Designed like a specialized Twitter or LinkedIn feed just for industry leaders.</p><ul><li>Discover high-performing content generated by top creators that is currently growing fast or has historically dominated.</li><li>Use these insights exclusively for <strong>content analyzing purposes</strong> to see why top-tier videos succeed and how you can apply those lessons to your channel.</li></ul><h3 id="_3-viraled-ai-wip" tabindex="-1">3. Viraled AI <em>(WIP)</em> <a class="header-anchor" href="#_3-viraled-ai-wip" aria-label="Permalink to &quot;3. Viraled AI *(WIP)*&quot;">​</a></h3><p>A next-gen suite of AI tools that will further simplify and elevate content creation. (Currently unclickable and under development).</p>',17)])])}const p=a(i,[["render",n]]);export{f as __pageData,p as default};
